import React from "react"


class User extends React.Component {
    user = this.props.user
    render() {
        return (
            <div className="user">
                <h3 style={{fontWeight: "bold"}}>{this.user.firstname}</h3>
                <h4 style={{color: "white", fontWeight: "1000px"}}>{this.user.info}</h4>
            </div>
        )
    }
}



export default User
